297	func GetModel(name string) (*Model, error) {
298		n := model.ParseName(name)
299		mf, err := manifest.ParseNamedManifest(n)
300		if err != nil {
301			return nil, err
302		}
303	
304		m := &Model{
305			Name:      n.String(),
306			ShortName: n.DisplayShortest(),
307			Digest:    mf.Digest(),
308			Template:  template.DefaultTemplate,
309		}
310	
311		if mf.Config.Digest != "" {
312			filename, err := manifest.BlobsPath(mf.Config.Digest)
313			if err != nil {
314				return nil, err
315			}
316	
317			configFile, err := os.Open(filename)
318			if err != nil {
319				return nil, err
320			}
321			defer configFile.Close()
322	
323			if err := json.NewDecoder(configFile).Decode(&m.Config); err != nil {
324				return nil, err
325			}
326		}
327	
328		for _, layer := range mf.Layers {
329			filename, err := manifest.BlobsPath(layer.Digest)
330			if err != nil {
331				return nil, err
332			}
333	
334			switch layer.MediaType {
335			case "application/vnd.ollama.image.model":
336				m.ModelPath = filename
337				m.ParentModel = layer.From
338			case "application/vnd.ollama.image.embed":
339				// Deprecated in versions  > 0.1.2
340				// TODO: remove this warning in a future version
341				slog.Info("WARNING: model contains embeddings, but embeddings in modelfiles have been deprecated and will be ignored.")
342			case "application/vnd.ollama.image.adapter":
343				m.AdapterPaths = append(m.AdapterPaths, filename)
344			case "application/vnd.ollama.image.projector":
345				m.ProjectorPaths = append(m.ProjectorPaths, filename)
346			case "application/vnd.ollama.image.prompt",
347				"application/vnd.ollama.image.template":
348				bts, err := os.ReadFile(filename)
349				if err != nil {
350					return nil, err
351				}
352	
353				m.Template, err = template.Parse(string(bts))
354				if err != nil {
355					return nil, err
356				}
357			case "application/vnd.ollama.image.system":
358				bts, err := os.ReadFile(filename)
359				if err != nil {
360					return nil, err
361				}
362	
363				m.System = string(bts)
364			case "application/vnd.ollama.image.params":
365				params, err := os.Open(filename)
366				if err != nil {
367					return nil, err
368				}
369				defer params.Close()
370	
371				// parse model options parameters into a map so that we can see which fields have been specified explicitly
372				if err = json.NewDecoder(params).Decode(&m.Options); err != nil {
373					return nil, err
374				}
375			case "application/vnd.ollama.image.messages":
376				msgs, err := os.Open(filename)
377				if err != nil {
378					return nil, err
379				}
380				defer msgs.Close()
381	
382				if err = json.NewDecoder(msgs).Decode(&m.Messages); err != nil {
383					return nil, err
384				}
385			case "application/vnd.ollama.image.license":
386				bts, err := os.ReadFile(filename)
387				if err != nil {
388					return nil, err
389				}
390				m.License = append(m.License, string(bts))
391			}
392		}
393	
394		return m, nil
395	}
